import{_ as o,o as a,c as r,ai as e}from"./chunks/framework.DMjte4z8.js";const p=JSON.parse('{"title":"触发器变量与数据类型","description":"","frontmatter":{"title":"触发器变量与数据类型","category":"triggers","updated":"2026-05-07T00:00:00.000Z","model":"minimax/MiniMax-M2.7-highspeed","quality_score":0.83,"discovered_via":"manual","sources":["https://www.thehelper.net/threads/jass-tutorial-in-detail.121427/","https://www.hiveworkshop.com/threads/basics-of-triggers.32113/","https://github.com/TheLazzoro/BetterTriggers","https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=19780"]},"headers":[],"relativePath":"triggers/触发器变量与数据类型.md","filePath":"triggers/触发器变量与数据类型.md","lastUpdated":1779351155000}'),s={name:"triggers/触发器变量与数据类型.md"};function n(l,t,i,h,g,u){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="触发器变量与数据类型" tabindex="-1">触发器变量与数据类型 <a class="header-anchor" href="#触发器变量与数据类型" aria-label="Permalink to “触发器变量与数据类型”">​</a></h1><h2 id="什么是触发器变量" tabindex="-1">什么是触发器变量？ <a class="header-anchor" href="#什么是触发器变量" aria-label="Permalink to “什么是触发器变量？”">​</a></h2><p>本节将带你认识<strong>触发器变量</strong>——这是地图制作中最基础但最重要的概念之一。学完本节后，你将理解变量是什么，以及为什么几乎所有复杂的触发器都离不开它。</p><h3 id="变量的基本概念" tabindex="-1">变量的基本概念 <a class="header-anchor" href="#变量的基本概念" aria-label="Permalink to “变量的基本概念”">​</a></h3><p><strong>变量</strong>就像一个可以存放东西的盒子。你给这个盒子起一个名字（比如&quot;血量&quot;、&quot;玩家金币&quot;），然后可以在触发器里往里面放东西或者取东西使用。</p><p>在魔兽争霸III的触发器编辑器中，变量可以存储多种类型的值：数字、文字、单位、位置坐标等<a href="./触发器是地图逻辑的核心，通过组合事件、条件、动作来实现游戏机制。">^2</a>。</p><h3 id="为什么需要使用变量" tabindex="-1">为什么需要使用变量 <a class="header-anchor" href="#为什么需要使用变量" aria-label="Permalink to “为什么需要使用变量”">​</a></h3><p>想象你要制作一个RPG地图：玩家杀死怪物后获得金币。你需要记录&quot;玩家当前有多少金币&quot;，这时候变量就派上用场了——它会记住这个数值，下一次玩家又杀死怪物时，触发器会把变量里的数字加上新获得的金币，再存回去[^4]。</p><blockquote><p><strong>💡 新手提示</strong>：没有变量的话，你只能写&quot;固定&quot;的行为——比如每次奖励100金币。但有了变量，你可以让奖励根据玩家等级、装备等动态变化。</p></blockquote><h3 id="变量命名规范与建议" tabindex="-1">变量命名规范与建议 <a class="header-anchor" href="#变量命名规范与建议" aria-label="Permalink to “变量命名规范与建议”">​</a></h3><p>起名字时注意以下几点：</p><ol><li><strong>使用有意义的中文名称</strong> — 比如&quot;当前英雄&quot;比&quot;变量1&quot;更容易理解</li><li><strong>避免使用纯数字或单个字母</strong> — 除非是临时变量</li><li><strong>保持命名一致性</strong> — 比如所有表示玩家的变量都以&quot;玩家&quot;开头</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常用&quot;temp&quot;或&quot;tmp&quot;这样的缩写给很多变量命名，过几天回头看完全不知道每个变量是做什么的。建议一开始就养成好习惯！</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>现在你明白了：**变量是一个用来存储和重复使用数据&quot;的&quot;容器&quot;。它是让你的地图具有&quot;记忆&quot;和&quot;变化&quot;能力的基础。</p><h2 id="常用数据类型详解" tabindex="-1">常用数据类型详解 <a class="header-anchor" href="#常用数据类型详解" aria-label="Permalink to “常用数据类型详解”">​</a></h2><p>本节将详细介绍触发器中最常用的几种数据类型，帮助你理解它们的区别和使用场景。学完本节后，你将能够根据实际需求选择合适的数据类型，避免因类型错误导致的触发器问题。</p><hr><h3 id="整数-integer-与实数-real-的区别" tabindex="-1">整数(Integer)与实数(Real)的区别 <a class="header-anchor" href="#整数-integer-与实数-real-的区别" aria-label="Permalink to “整数(Integer)与实数(Real)的区别”">​</a></h3><p><strong>整数（Integer）</strong> 是指没有小数点的完整数字，比如 1、100、-5。它适合用来表示可以&quot;一个个数&quot;的东西，比如：玩家的金币数量、单位被击杀的次数、倒计时的秒数等<a href="./触发器是地图逻辑的核心，通过组合事件、条件、动作来实现游戏机制。">^2</a>。</p><p><strong>实数（Real）</strong> 是指带小数点的数字，比如 3.14、100.5、-0.5。它适合表示需要&quot;精确测量&quot;的东西，比如：单位的生命值 500.0、技能的伤害值 125.5、移动速度 300.0 等。</p><blockquote><p><strong>💡 新手提示</strong>：简单记忆方法是——能用&quot;个&quot;来计数的用整数，需要&quot;精确一点&quot;的用实数。比如金币用整数（100金币），但扣血计算时可能用到实数（造成 25.5 点伤害）。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手会把实数赋值给整数变量，或者反过来。比如你计算&quot;生命值的 30%&quot;得到 150.5，如果存到整数变量里，编辑器会自动把小数部分<strong>截断</strong>（变成150），导致实际扣血比预期少！这在RPG游戏中会严重影响平衡性。解决方法：明确知道需要小数的值，一定要用<strong>实数</strong>类型的变量。</p></blockquote><p>两者的主要区别在于：<strong>整数</strong>处理的是&quot;完整的、离散的&quot;数据；<strong>实数</strong>处理的是&quot;连续的、精细的&quot;数据。在创建变量时想清楚，这个值会不会出现小数点？如果会，就用实数。</p><hr><h3 id="字符串-string-的用法" tabindex="-1">字符串(String)的用法 <a class="header-anchor" href="#字符串-string-的用法" aria-label="Permalink to “字符串(String)的用法”">​</a></h3><p><strong>字符串（String）</strong> 专门用来存储<strong>文字内容</strong>，比如玩家的名字、物品的描述、屏幕上的提示信息等。</p><p>在触发器中，字符串用英文双引号包裹，例如：<code>&quot;你好，冒险者！&quot;</code>、<code>&quot;火焰剑&quot;</code>、<code>&quot;任务完成&quot;</code>。你可以把字符串理解为&quot;一串字符&quot;，无论是中文还是英文，都属于字符串类型。</p><p>字符串的常见用途包括：</p><ul><li><strong>显示提示信息</strong>：如&quot;你获得了100金币&quot;</li><li><strong>保存玩家输入</strong>：如玩家的聊天内容</li><li><strong>标记数据</strong>：如给单位起个名字方便识别</li></ul><blockquote><p><strong>💡 新手提示</strong>：字符串变量的创建方法和其他变量一样，只是在&quot;变量类型&quot;列表中选择 <strong>String</strong>。输入字符串内容时记得加英文双引号，否则编辑器可能把它当成变量名来处理。</p></blockquote><hr><h3 id="布尔-boolean-与单位类型" tabindex="-1">布尔(Boolean)与单位类型 <a class="header-anchor" href="#布尔-boolean-与单位类型" aria-label="Permalink to “布尔(Boolean)与单位类型”">​</a></h3><p><strong>布尔（Boolean）</strong> 是一种&quot;开关&quot;类型的数据，它只有两个可能的值：<strong>真（True）</strong> 或 <strong>假（False）</strong>。虽然看起来简单，但它在触发器中极其重要！</p><p>布尔类型专门用于<strong>条件判断</strong>。例如：</p><ul><li>&quot;这个单位还活着吗？&quot; → 真或假</li><li>&quot;玩家是否拥有这件装备？&quot; → 真或假</li><li>&quot;任务是否已完成？&quot; → 真或假</li></ul><p>触发器中的很多条件检查（如&quot;单位生命值大于0&quot;）本质上返回的就是布尔值<a href="./触发器是地图逻辑的核心，通过组合事件、条件、动作来实现游戏机制。">^2</a>。</p><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把布尔和整数混淆。比如用 1 代表&quot;是&quot;，用 0 代表&quot;否&quot;。虽然技术上可行，但这样做会让代码难以理解。 Warcraft III 的触发器有专门的布尔类型，应该<strong>直接使用布尔</strong>，而不是用整数来模拟开关。</p></blockquote><p><strong>单位类型（Unit）</strong> 是另一种特殊的数据类型，它专门用来<strong>存储一个游戏单位</strong>。注意，这里说的是&quot;整个单位对象&quot;，而不是单位的生命值或名字。</p><p>当你把一个单位赋值给单位类型变量后，就可以在后续的触发器中<strong>引用这个单位</strong>来做各种操作，比如：移动它、治疗它、让它施放技能等。</p><hr><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成本节内容后，你已经掌握了四种最常用的数据类型：</p><table tabindex="0"><thead><tr><th>数据类型</th><th>用途</th><th>举例</th></tr></thead><tbody><tr><td><strong>整数 Integer</strong></td><td>计数、秒数、金币等完整数字</td><td>100、-5、0</td></tr><tr><td><strong>实数 Real</strong></td><td>伤害、百分比、精确数值</td><td></td></tr></tbody></table><h2 id="创建和管理变量" tabindex="-1">创建和管理变量 <a class="header-anchor" href="#创建和管理变量" aria-label="Permalink to “创建和管理变量”">​</a></h2><p>在本节中，你将学习如何在魔兽争霸3世界编辑器中创建变量（用来存储临时数据的&quot;容器&quot;），以及理解变量的作用范围。学完本节后，你就能为自己的地图添加可重复使用的数据存储功能了。</p><h3 id="在变量编辑器中创建变量" tabindex="-1">在变量编辑器中创建变量 <a class="header-anchor" href="#在变量编辑器中创建变量" aria-label="Permalink to “在变量编辑器中创建变量”">​</a></h3><p>变量编辑器是集中管理所有变量的地方，适合创建<strong>全局变量</strong>（在整个地图中都可使用）。</p><ol><li><strong>打开变量编辑器</strong> — 在世界编辑器顶部菜单栏点击「触发器」菜单，然后选择「新建变量」<a href="./触发器是地图逻辑的核心，通过组合事件、条件、动作来实现游戏机制。">^2</a>（或使用快捷键Ctrl+B）[^4]</li><li><strong>设置变量名称</strong> — 在弹出的变量属性面板中，找到「变量名称」输入框，输入一个能描述变量用途的名字，比如 <code>玩家金币</code> 或 <code>当前单位</code></li><li><strong>选择数据类型</strong> — 在「变量类型」下拉菜单中选择合适的数据类型<a href="./变量是存储数据的基本容器，JASS会将代码编译后在游戏中执行。">^1</a>。常见类型包括： <ul><li><strong>整数（Integer）</strong>：存储整数值，如金币数量</li><li><strong>实数（Real）</strong>：存储小数，如生命值百分比</li><li><strong>字符串（String）</strong>：存储文字</li><li><strong>单位（Unit）</strong>：存储一个游戏单位</li></ul></li><li><strong>点击确定保存</strong> — 确认无误后点击「确定」按钮，变量就创建完成了</li></ol><blockquote><p><strong>💡 新手提示</strong>：变量名建议使用英文或拼音，避免使用中文命名。在JASS代码中，变量名必须是英文字母、数字和下划线的组合<a href="./变量是存储数据的基本容器，JASS会将代码编译后在游戏中执行。">^1</a>。</p></blockquote><h3 id="触发器内直接创建变量" tabindex="-1">触发器内直接创建变量 <a class="header-anchor" href="#触发器内直接创建变量" aria-label="Permalink to “触发器内直接创建变量”">​</a></h3><p>在触发器编辑器中，你也可以创建<strong>局部变量</strong>，只在该触发器内部使用。</p><ol><li><strong>打开触发器编辑器</strong> — 点击世界编辑器工具栏的「触发器编辑器」按钮<a href="./触发器是地图逻辑的核心，通过组合事件、条件、动作来实现游戏机制。">^2</a></li><li><strong>创建新触发器</strong> — 右键点击左侧触发器列表，选择「新建触发器」</li><li><strong>添加局部变量动作</strong> — 在触发器动作列表中，找到「设置变量」动作类别，添加「设置变量」动作</li><li><strong>定义新变量</strong> — 在弹出的变量选择器中，点击「新建变量」按钮，输入变量名并选择类型</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常混淆全局变量和局部变量。如果在一个触发器中创建的变量想在其他触发器中使用，必须在变量编辑器中创建（全局变量），而不是只在当前触发器内创建。</p></blockquote><h3 id="变量的作用域与生命周期" tabindex="-1">变量的作用域与生命周期 <a class="header-anchor" href="#变量的作用域与生命周期" aria-label="Permalink to “变量的作用域与生命周期”">​</a></h3><p>理解变量的<strong>作用域</strong>（Scope）和**生命周期）非常重要：</p><table tabindex="0"><thead><tr><th>类型</th><th>作用域</th><th>生命周期</th></tr></thead><tbody><tr><td>全局变量</td><td>整个地图所有触发器</td><td>从游戏开始到游戏结束</td></tr><tr><td>局部变量</td><td>仅在创建它的触发器内</td><td>仅在该触发器执行期间</td></tr></tbody></table><p>简单来说：</p><ul><li><strong>全局变量</strong>就像公共储物柜，任何人都能用，但会一直占用空间</li><li><strong>局部变量</strong>像一次性纸杯，用完就扔，不占用长期内存<a href="./BetterTriggers等自定义触发编辑器也遵循相同逻辑，只是界面有所改进。">^3</a></li></ul><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够：</p><ul><li>✅ 使用变量编辑器创建全局变量</li><li>✅ 在触发器内创建局部变量</li><li>✅ 区分全局变量和局部变量的使用场景</li></ul><blockquote><p><strong>💡 新手提示</strong>：刚开始做地图时，建议先多用全局变量。虽然局部变量更节省资源，但全局变量更容易理解和调试。等熟悉了触发器的工作原理后，再逐步使用局部变量优化你的地图。</p></blockquote><h2 id="变量数组入门" tabindex="-1">变量数组入门 <a class="header-anchor" href="#变量数组入门" aria-label="Permalink to “变量数组入门”">​</a></h2><p>本节将教你理解<strong>变量数组</strong>的概念，以及如何将<strong>循环</strong>与数组配合使用来高效处理大量数据。学完本节后，你将能够用数组存储多个同类信息，并自动遍历处理它们。</p><h3 id="什么是变量数组" tabindex="-1">什么是变量数组 <a class="header-anchor" href="#什么是变量数组" aria-label="Permalink to “什么是变量数组”">​</a></h3><h4 id="基础概念" tabindex="-1">基础概念 <a class="header-anchor" href="#基础概念" aria-label="Permalink to “基础概念”">​</a></h4><p>在理解数组之前，先回忆一下<strong>普通变量</strong>的作用。普通变量就像一个带锁的盒子，你放进一个值（比如数字5），下次打开时还是5<a href="./变量是存储数据的基本容器，JASS会将代码编译后在游戏中执行。">^1</a>。</p><p><strong>变量数组</strong>则不同——它像一排编好号码的储物柜。每个柜子都能存放一个值，而柜子的编号叫做<strong>索引</strong>（Index）。你可以把数组想象成这样的结构：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>变量名[1] = &quot;第一个值&quot;</span></span>
<span class="line"><span>变量名[2] = &quot;第二个值&quot;</span></span>
<span class="line"><span>变量名[3] = &quot;第三个值&quot;</span></span>
<span class="line"><span>...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h4 id="为什么需要数组" tabindex="-1">为什么需要数组？ <a class="header-anchor" href="#为什么需要数组" aria-label="Permalink to “为什么需要数组？”">​</a></h4><p>假设你要记录10个单位的生命值。如果用普通变量，你需要创建10个变量：<code>HP_1</code>、<code>HP_2</code>、<code>HP_3</code>……这样既难管理，代码也会变得冗长<a href="./触发器是地图逻辑的核心，通过组合事件、条件、动作来实现游戏机制。">^2</a>。</p><p>用数组就简单多了！你只需要创建一个数组变量<code>HP</code>，然后用<code>HP[1]</code>、<code>HP[2]</code>……来访问每个单位的生命值。</p><h4 id="如何在触发器中创建数组" tabindex="-1">如何在触发器中创建数组 <a class="header-anchor" href="#如何在触发器中创建数组" aria-label="Permalink to “如何在触发器中创建数组”">​</a></h4><ol><li><strong>打开触发编辑器</strong> — 在顶部菜单栏点击&quot;触发器&quot;（或使用快捷键F4）</li><li><strong>新建变量</strong> — 在左侧变量列表区域，右键点击 → 选择&quot;新建变量&quot;</li><li><strong>设置数组属性</strong> — 在弹出的变量设置窗口中： <ul><li><strong>变量名称</strong>：输入你想要的名称（如 <code>玩家金币</code>）</li><li><strong>变量类型</strong>：在下拉菜单中选择数据类型（如&quot;整数&quot;、&quot;实数&quot;等）</li><li><strong>勾选&quot;数组&quot;选项</strong> — 这是关键步骤！</li><li><strong>数组大小</strong>：默认为1，可以设置为更大的数字（如10、20）<a href="./BetterTriggers等自定义触发编辑器也遵循相同逻辑，只是界面有所改进。">^3</a></li></ul></li><li><strong>点击确认</strong> — 变量创建完成</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记勾选&quot;数组&quot;选项，导致创建的其实是普通变量而非数组。另一个常见错误是将数组大小设为0，这样数组将无法存储任何数据。</p></blockquote><h3 id="循环与数组的配合使用" tabindex="-1">循环与数组的配合使用 <a class="header-anchor" href="#循环与数组的配合使用" aria-label="Permalink to “循环与数组的配合使用”">​</a></h3><h4 id="循环的作用" tabindex="-1">循环的作用 <a class="header-anchor" href="#循环的作用" aria-label="Permalink to “循环的作用”">​</a></h4><p><strong>循环</strong>是让计算机自动重复执行某段代码的机制。没有循环，你要处理10个单位的伤害，就必须写10次&quot;扣血&quot;代码。有了循环，同样的操作只需写一次<a href="./触发器是地图逻辑的核心，通过组合事件、条件、动作来实现游戏机制。">^2</a>。</p><h4 id="循环的创建步骤" tabindex="-1">循环的创建步骤 <a class="header-anchor" href="#循环的创建步骤" aria-label="Permalink to “循环的创建步骤”">​</a></h4><ol><li><strong>选择触发器</strong> — 打开你想添加循环的触发器</li><li><strong>添加动作</strong> — 在右侧动作列表中，找到&quot;一般&quot;分类</li><li><strong>选择&quot;为每个整数从A到B执行动作&quot;</strong> — 这个动作就是最常用的循环结构</li><li><strong>设置循环参数</strong>： <ul><li><strong>起始值</strong>：通常写一个变量名（如 <code>i</code>），初始值设为1</li><li><strong>结束值</strong>：设为数组的最大索引（如 10）</li></ul></li><li><strong>在循环内部添加处理动作</strong> — 拖入你想重复执行的动作，使用 <code>[变量名][i]</code> 来引用当前循环对应的数组元素<a href="./BetterTriggers等自定义触发编辑器也遵循相同逻辑，只是界面有所改进。">^3</a></li></ol><h4 id="实用示例-给所有玩家发放金币" tabindex="-1">实用示例：给所有玩家发放金币 <a class="header-anchor" href="#实用示例-给所有玩家发放金币" aria-label="Permalink to “实用示例：给所有玩家发放金币”">​</a></h4><p>假设你有5个玩家，你想给每个玩家发放100金币：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>事件：当游戏开始时</span></span>
<span class="line"><span>条件：无</span></span>
<span class="line"><span>动作：</span></span>
<span class="line"><span>    为每个整数从 1 到 5 执行动作</span></span>
<span class="line"><span>        循环 - 执行动作</span></span>
<span class="line"><span>            设置 玩家金币[此整数] = 玩家金币[此整数] + 100</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>在这个例子中，<code>此整数</code>就是循环计数器。当循环执行到第1次时，<code>此整数</code>=1，数组访问的是<code>玩家金币[1]</code>；第2次循环时访问<code>玩家金币[2]</code>……以此类推。</p><blockquote><p><strong>💡 新手提示</strong>：循环变量名（如<code>此整数</code>）只是&quot;临时计数器&quot;，每次循环会变化。你完全可以用数组的索引来访问对应的数组元素，而不用担心记不住当前是第几次循环。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该已经：</p><ul><li>✅ 理解<strong>普通变量</strong>与<strong>数组变量</strong>的区别</li><li>✅ 学会在触发编辑器中<strong>创建数组变量</strong></li><li>✅ 掌握使用<strong>循环结构</strong>遍历数组的方法</li><li>✅ 能够编写&quot;为所有玩家执行某操作&quot;的通用代码</li></ul><p>数组配合循环是地图制作中最常用的技巧之一。掌握它们之后，你就可以用简洁的代码处理大量数据，让你的RPG地图逻辑更加高效强大！</p><h2 id="实用示例与常见错误" tabindex="-1">实用示例与常见错误 <a class="header-anchor" href="#实用示例与常见错误" aria-label="Permalink to “实用示例与常见错误”">​</a></h2><p>本节将通过三个实用示例教你如何正确使用触发器变量与数据类型，并学习如何避免最常见的新手错误。学完本节后，你将能够独立创建存储游戏数据的变量，并学会处理数据类型不匹配和空值问题。</p><h3 id="存储单位信息示例" tabindex="-1">存储单位信息示例 <a class="header-anchor" href="#存储单位信息示例" aria-label="Permalink to “存储单位信息示例”">​</a></h3><p>在实际地图中，你经常需要记住某个单位的信息。比如当玩家选中一个英雄时，记住这个英雄以便之后使用。以下是具体步骤：</p><ol><li><p><strong>第一步：创建变量</strong> — 在触发器编辑器左侧，点击&quot;变量&quot;列表，然后点击&quot;新建变量&quot;按钮<a href="./触发器是地图逻辑的核心，通过组合事件、条件、动作来实现游戏机制。">^2</a>。在弹出的对话框中，将变量名称改为<code>已选英雄</code>，变量类型选择&quot;单位&quot;[^4]。</p></li><li><p><strong>第二步：设置变量值</strong> — 新建一个触发器，事件设为&quot;玩家 - 玩家1选择单位&quot;。动作添加&quot;设置变量 - 已选英雄 = 被选择的单位&quot;[^4]。这样每次玩家1选择单位时，变量就会记住当前选中的单位。</p></li><li><p><strong>第三步：使用变量</strong> — 你可以在其他触发器中引用<code>已选英雄</code>变量。比如创建一个触发器：当玩家1按M键时，让<code>已选英雄</code>发出&quot;移动&quot;指令。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：变量名最好用英文或拼音命名，避免使用中文字符。虽然触发器编辑器支持中文变量名，但在某些情况下可能导致问题。</p></blockquote><h3 id="数据类型不匹配问题" tabindex="-1">数据类型不匹配问题 <a class="header-anchor" href="#数据类型不匹配问题" aria-label="Permalink to “数据类型不匹配问题”">​</a></h3><p>数据类型不匹配是新手最常遇到的错误之一。想象一下，你尝试把一个整数（如&quot;100&quot;）当作单位类型使用，编辑器就无法正确执行。</p><ol><li><p><strong>第一步：理解类型对应关系</strong> — 触发器中每种数据都有明确的类型<a href="./变量是存储数据的基本容器，JASS会将代码编译后在游戏中执行。">^1</a>。例如&quot;单位&quot;类型只能存放单位，&quot;整数&quot;类型只能存放数字，&quot;字符串&quot;类型只能存放文字。如果类型不对，触发器会报错或直接忽略这条指令。</p></li><li><p><strong>第二步：检查函数返回值类型</strong> — 当你使用&quot;获取触发单位&quot;这样的函数时，它返回的是一个&quot;单位&quot;类型的值[^4]。如果你把这个值赋给一个&quot;整数&quot;类型的变量，就会出现类型不匹配错误。</p></li><li><p><strong>第三步：使用类型转换函数</strong> — Warcraft III提供了一些转换函数。比如&quot;整数转字符串&quot;可以将数字123变成文字&quot;123&quot;。在触发器动作中搜索&quot;转换&quot;即可找到这些函数。</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手会把单位（Unit）和单位类型（Unit Type）搞混。单位是指战场上具体存在的某个角色，而单位类型是指所有同类型单位的共同特征模板[4]。如果你想判断一个单位是不是&quot;骑士&quot;，应该用&quot;单位类型等于&quot;而不是&quot;单位等于&quot;。</p></blockquote><h3 id="空值-null-处理" tabindex="-1">空值(Null)处理 <a class="header-anchor" href="#空值-null-处理" aria-label="Permalink to “空值(Null)处理”">​</a></h3><p>&quot;空值&quot;（也称Null）是指变量没有存储任何有效数据的情况。就像一个空盒子——你定义了变量，但还没有往里面放东西。</p><ol><li><p><strong>第一步：认识空值</strong> — 当你创建一个新变量但还没有设置它的值时，这个变量就是空值。在触发器中，空值的条件判断结果是&quot;假&quot;，这意味着&quot;如果变量等于空值&quot;这个条件通常会成立<a href="./BetterTriggers等自定义触发编辑器也遵循相同逻辑，只是界面有所改进。">^3</a>。</p></li><li><p><strong>第二步：预防空值错误</strong> — 在使用变量之前，务必检查它是否为空。比如你创建了<code>当前单位</code>变量，在使用它之前应该添加条件判断：&quot;如果 当前单位 不等于 空值&quot;，然后才执行后续操作<a href="./BetterTriggers等自定义触发编辑器也遵循相同逻辑，只是界面有所改进。">^3</a>。</p></li><li><p><strong>第三步：处理可能的空值情况</strong> — 如果你的触发器中单位可能不存在（比如某个玩家没有英雄），一定要在使用前检查。可以使用&quot;如果...那么...否则&quot;结构：当变量为空时做一件事，不为空时做另一件事。</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手会遇到&quot;空引用&quot;错误导致地图崩溃。这是因为地图在尝试使用一个空变量时找不到对应的数据。解决方法是在使用变量前总是检查它是否为空[3]。这是一个好习惯，可以让你的地图更加稳定。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上三个示例的学习后，你应该已经掌握了创建和使用变量存储数据的方法，能够识别并避免数据类型不匹配的错误，以及学会正确处理可能出现的空值情况。建议你打开World Editor，动手创建一个包含这些元素的测试触发器，亲身体验一下这些概念的实际运用。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p><a href="./变量是存储数据的基本容器，JASS会将代码编译后在游戏中执行。">^1</a>: <a href="https://www.thehelper.net/threads/jass-tutorial-in-detail.121427/" target="_blank" rel="noreferrer">Tutorial - JASS Tutorial, in detail | The Helper</a> — accessed 2026-05-07 <a href="./触发器是地图逻辑的核心，通过组合事件、条件、动作来实现游戏机制。">^2</a>: <a href="https://www.hiveworkshop.com/threads/basics-of-triggers.32113/" target="_blank" rel="noreferrer">Basics of Triggers - HIVE</a> — accessed 2026-05-07 <a href="./BetterTriggers等自定义触发编辑器也遵循相同逻辑，只是界面有所改进。">^3</a>: <a href="https://github.com/TheLazzoro/BetterTriggers" target="_blank" rel="noreferrer">GitHub - TheLazzoro/BetterTriggers: A custom Warcraft III trigger...</a> — accessed 2026-05-07 [^4]: <a href="https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=19780" target="_blank" rel="noreferrer">Triggers - Basic Guide - Warcraft III World Editor</a> — accessed 2026-05-07</p>`,108)])])}const c=o(s,[["render",n]]);export{p as __pageData,c as default};
